using BenchmarkDotNet.Attributes;
using BenchmarkDotNet.Configs;

namespace ConstExpr.Benchmarks.MathTests;

/// <summary>
/// Compares Math.Atan2 against the FastAtan2 approximations generated by Atan2FunctionOptimizer.
/// Also benchmarks two improved scalar alternatives per precision group.
///
/// Two type groups are benchmarked independently:
///   Float  – MathF.Atan2  vs FastAtan2(float)    (branched Padé [2/2], max error ≈ 2.5e-2 rad)
///                         vs FastAtan2V2(float)   (branchless A&amp;S §4.4.43 minimax, max error ≈ 1.1e-5 rad)
///                         vs FastAtan2V3(float)   (2-term ultra-fast poly, max error ≈ 5e-3 rad)
///   Double – Math.Atan2   vs FastAtan2(double)   (same branched Padé, max error ≈ 2.5e-2 rad)
///                         vs FastAtan2V2(double)  (same A&amp;S minimax in double arithmetic, max error ≈ 1.1e-5 rad)
///                         vs FastAtan2V3(double)  (half-angle + 8-term Taylor, max error ≈ 4e-8 rad)
///
/// Accuracy notes:
///   Current Padé: z*(15+4z²)/(z⁴+9z²+15) — matches Taylor to O(z³) only; error at z=1 is ~2.5%.
///   V2 poly (A&amp;S §4.4.43): 5-coefficient minimax, error ~1.1e-5 rad; 2000× better than current.
///   V3 float: 2-term poly atan(a)≈a*(1.0583981−0.273*a); fastest scalar, error ~5e-3 rad.
///   V3 double: half-angle t=a/(1+√(1+a²)) reduces [0,1]→[0,tan(π/8)], then 8-term Taylor, error ~4e-8 rad.
///
/// Run command:
///   dotnet run -c Release --project ConstExpr.Benchmarks/ConstExpr.Benchmarks.csproj --filter '*Atan2Benchmark*'
/// </summary>
[MemoryDiagnoser]
[GroupBenchmarksBy(BenchmarkLogicalGroupRule.ByCategory)]
[CategoriesColumn]
public class Atan2Benchmark
{
	// 1 024 (y, x) pairs uniformly distributed over [-2, 2] × [-2, 2].
	// All four quadrants are represented so branch-prediction pressure is realistic.
	private const int N = 1_024;
	private float[] _floatY = null!;
	private float[] _floatX = null!;
	private double[] _doubleY = null!;
	private double[] _doubleX = null!;

	[GlobalSetup]
	public void Setup()
	{
		var rng = new Random(42);
		_floatY = new float[N];
		_floatX = new float[N];
		_doubleY = new double[N];
		_doubleX = new double[N];

		for (var i = 0; i < N; i++)
		{
			var y = rng.NextDouble() * 4.0 - 2.0; // uniform in [-2, 2]
			var x = rng.NextDouble() * 4.0 - 2.0;
			_floatY[i] = (float) y;
			_floatX[i] = (float) x;
			_doubleY[i] = y;
			_doubleX[i] = x;
		}
	}

	// ── float ──────────────────────────────────────────────────────────────

	/// <summary>Built-in MathF.Atan2 — hardware-accurate, full-precision float result.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float DotNetAtan2_Float()
	{
		var sum = 0f;
		for (var i = 0; i < N; i++)
			sum += MathF.Atan2(_floatY[i], _floatX[i]);
		return sum;
	}

	/// <summary>
	/// Current FastAtan2(float) from Atan2FunctionOptimizer — branched Padé [2/2] rational approximant.
	/// Formula: z*(15+4z²) / (z⁴+9z²+15), two code paths depending on |x|≥|y|.
	/// Max absolute error ≈ 2.5e-2 rad (at 45° angles where z=1).
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAtan2_Float()
	{
		var sum = 0f;
		for (var i = 0; i < N; i++)
			sum += CurrentFastAtan2Float(_floatY[i], _floatX[i]);
		return sum;
	}

	/// <summary>
	/// FastAtan2V2(float) — branchless octant reduction + 5-term A&amp;S §4.4.43 minimax polynomial.
	/// atan(a) ≈ a*(a₁ + u*(a₃ + u*(a₅ + u*(a₇ + u*a₉)))) on reduced a ∈ [0, 1], u = a².
	/// 4 FMAs + 1 mul; no rational division in the core.
	/// Max absolute error ≈ 1.1e-5 rad — 2000× more accurate than the current Padé.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAtan2V2_Float()
	{
		var sum = 0f;
		for (var i = 0; i < N; i++)
			sum += FastAtan2FloatV2(_floatY[i], _floatX[i]);
		return sum;
	}

	/// <summary>
	/// FastAtan2V3(float) — branchless octant reduction + 2-term polynomial.
	/// atan(a) ≈ a*(1.0583981 − 0.273*a): 1 FMA + 1 mul; fastest scalar variant.
	/// Coefficients ensure atan(0)=0 and atan(1)=π/4 exactly; 0.273 minimises max error.
	/// Max absolute error ≈ 5e-3 rad.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Float")]
	public float FastAtan2V3_Float()
	{
		var sum = 0f;
		for (var i = 0; i < N; i++)
			sum += FastAtan2FloatV3(_floatY[i], _floatX[i]);
		return sum;
	}

	// ── double ─────────────────────────────────────────────────────────────

	/// <summary>Built-in Math.Atan2 — hardware-accurate, full-precision double result.</summary>
	[Benchmark(Baseline = true, OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double DotNetAtan2_Double()
	{
		var sum = 0.0;
		for (var i = 0; i < N; i++)
			sum += Math.Atan2(_doubleY[i], _doubleX[i]);
		return sum;
	}

	/// <summary>
	/// Current FastAtan2(double) from Atan2FunctionOptimizer — same branched Padé as float version.
	/// Max absolute error ≈ 2.5e-2 rad.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAtan2_Double()
	{
		var sum = 0.0;
		for (var i = 0; i < N; i++)
			sum += CurrentFastAtan2Double(_doubleY[i], _doubleX[i]);
		return sum;
	}

	/// <summary>
	/// FastAtan2V2(double) — branchless octant reduction + 5-term A&amp;S §4.4.43 minimax polynomial
	/// evaluated in double arithmetic (same coefficients as V2 float).
	/// Max absolute error ≈ 1.1e-5 rad.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAtan2V2_Double()
	{
		var sum = 0.0;
		for (var i = 0; i < N; i++)
			sum += FastAtan2DoubleV2(_doubleY[i], _doubleX[i]);
		return sum;
	}

	/// <summary>
	/// FastAtan2V3(double) — branchless octant reduction + half-angle reduction + 8-term Taylor series.
	/// Half-angle identity: atan(a) = 2*atan(t),  t = a/(1+√(1+a²)),  maps a∈[0,1] → t∈[0,tan(π/8)].
	/// Taylor on the reduced interval: truncation error ≤ t^17/17 ≈ (0.414)^17/17 ≈ 1.8e-8 rad,
	/// doubling for the 2× factor: max absolute error ≈ 4e-8 rad.
	/// One sqrt, no branches in the core.
	/// </summary>
	[Benchmark(OperationsPerInvoke = N)]
	[BenchmarkCategory("Double")]
	public double FastAtan2V3_Double()
	{
		var sum = 0.0;
		for (var i = 0; i < N; i++)
			sum += FastAtan2DoubleV3(_doubleY[i], _doubleX[i]);
		return sum;
	}

	// ── current implementations (exact mirror of Atan2FunctionOptimizer generated code) ──

	private static float CurrentFastAtan2Float(float y, float x)
	{
		if (float.IsNaN(y) || Single.IsNaN(x)) return Single.NaN;
		if (y == 0.0f && x == 0.0f) return 0.0f;

		var absY = Single.Abs(y);
		var absX = Single.Abs(x);
		float angle;

		if (absX >= absY)
		{
			var z = y / x;
			var z2 = z * z;
			var z4 = z2 * z2;
			var numerator = Single.FusedMultiplyAdd(4.0f, z2, 15.0f);
			numerator *= z;
			var denominator = Single.FusedMultiplyAdd(9.0f, z2, 15.0f);
			denominator = z4 + denominator;
			angle = numerator / denominator;
			if (Single.IsNegative(x))
				angle = y >= 0.0f ? Single.Pi + angle : angle - Single.Pi;
		}
		else
		{
			var z = x / y;
			var z2 = z * z;
			var z4 = z2 * z2;
			var numerator = Single.FusedMultiplyAdd(4.0f, z2, 15.0f);
			numerator *= z;
			var denominator = Single.FusedMultiplyAdd(9.0f, z2, 15.0f);
			denominator = z4 + denominator;
			var baseAngle = numerator / denominator;
			angle = y >= 0.0f ? Single.Pi / 2 - baseAngle : -Single.Pi / 2 - baseAngle;
		}

		return angle;
	}

	private static double CurrentFastAtan2Double(double y, double x)
	{
		if (Double.IsNaN(y) || Double.IsNaN(x)) return Double.NaN;
		if (y == 0.0 && x == 0.0) return 0.0;

		var absY = Double.Abs(y);
		var absX = Double.Abs(x);
		double angle;

		if (absX >= absY)
		{
			var z = y / x;
			var z2 = z * z;
			var z4 = z2 * z2;
			var numerator = Double.FusedMultiplyAdd(4.0, z2, 15.0);
			numerator *= z;
			var denominator = Double.FusedMultiplyAdd(9.0, z2, 15.0);
			denominator = z4 + denominator;
			angle = numerator / denominator;
			if (Double.IsNegative(x))
				angle = y >= 0.0 ? Double.Pi + angle : angle - Double.Pi;
		}
		else
		{
			var z = x / y;
			var z2 = z * z;
			var z4 = z2 * z2;
			var numerator = Double.FusedMultiplyAdd(4.0, z2, 15.0);
			numerator *= z;
			var denominator = Double.FusedMultiplyAdd(9.0, z2, 15.0);
			denominator = z4 + denominator;
			var baseAngle = numerator / denominator;
			angle = y >= 0.0 ? Double.Pi / 2 - baseAngle : -Double.Pi / 2 - baseAngle;
		}

		return angle;
	}

	// ── improved implementations ────────────────────────────────────────────

	/// <summary>
	/// Branchless octant reduction: a = min(|x|,|y|)/max(|x|,|y|) ∈ [0,1],
	/// then evaluate the A&amp;S §4.4.43 5-term minimax polynomial.
	/// Sign/quadrant corrections compile to conditional moves on x86 and ARM.
	/// </summary>
	private static float FastAtan2FloatV2(float y, float x)
	{
		if (Single.IsNaN(y) || Single.IsNaN(x)) return Single.NaN;
		var absX = Single.Abs(x);
		var absY = Single.Abs(y);
		var maxV = Single.Max(absX, absY);
		if (maxV == 0f) return 0f;

		var a = Single.Min(absX, absY) / maxV; // a ∈ [0, 1]
		var u = a * a;

		// Horner evaluation of atan(a)/a as polynomial in u = a²
		// Coefficients: Abramowitz & Stegun §4.4.43, max |ε| ≤ 1.1e-5 rad
		var p = Single.FusedMultiplyAdd(u, 0.0208351f, -0.0851330f);
		p = Single.FusedMultiplyAdd(u, p, 0.1801410f);
		p = Single.FusedMultiplyAdd(u, p, -0.3302995f);
		p = Single.FusedMultiplyAdd(u, p, 0.9998660f);
		p *= a;

		// Octant and quadrant corrections — all compile to conditional-move instructions
		p = absY > absX ? 1.5707963268f - p : p; // if |y|>|x|: angle = π/2 − atan(|x|/|y|)
		p = x < 0f ? 3.14159265359f - p : p; // quadrants II / III
		p = y < 0f ? -p : p; // quadrants III / IV
		return p;
	}

	/// <summary>
	/// Ultra-fast: 1 FMA + 1 mul in the polynomial core.
	/// atan(a) ≈ a*(1.0583981 − 0.273*a) for a ∈ [0,1]:
	/// constructed so atan(0)=0 and atan(1)=π/4 exactly; 0.273 minimises max absolute error.
	/// </summary>
	private static float FastAtan2FloatV3(float y, float x)
	{
		if (Single.IsNaN(y) || Single.IsNaN(x)) return Single.NaN;
		var absX = Single.Abs(x);
		var absY = Single.Abs(y);
		var maxV = Single.Max(absX, absY);
		if (maxV == 0f) return 0f;

		var a = Single.Min(absX, absY) / maxV; // a ∈ [0, 1]

		// 2-term: atan(a) ≈ a*(π/4 + 0.273*(1 − a)) = a*((π/4+0.273) − 0.273*a)
		var p = Single.FusedMultiplyAdd(-0.273f, a, 1.0583981f) * a;

		p = absY > absX ? 1.5707963268f - p : p;
		p = x < 0f ? 3.14159265359f - p : p;
		p = y < 0f ? -p : p;
		return p;
	}

	/// <summary>
	/// Same A&amp;S §4.4.43 5-term polynomial as FastAtan2FloatV2, evaluated in double arithmetic.
	/// The max error is still bounded by the polynomial approximation: ≈ 1.1e-5 rad.
	/// </summary>
	private static double FastAtan2DoubleV2(double y, double x)
	{
		if (Double.IsNaN(y) || Double.IsNaN(x)) return Double.NaN;
		var absX = Double.Abs(x);
		var absY = Double.Abs(y);
		var maxV = Double.Max(absX, absY);
		if (maxV == 0.0) return 0.0;

		var a = Double.Min(absX, absY) / maxV; // a ∈ [0, 1]
		var u = a * a;

		// A&S §4.4.43 minimax coefficients in double arithmetic
		var p = Double.FusedMultiplyAdd(u, 0.0208351, -0.0851330);
		p = Double.FusedMultiplyAdd(u, p, 0.1801410);
		p = Double.FusedMultiplyAdd(u, p, -0.3302995);
		p = Double.FusedMultiplyAdd(u, p, 0.9998660);
		p *= a;

		p = absY > absX ? Math.PI / 2.0 - p : p;
		p = x < 0.0 ? Math.PI - p : p;
		p = y < 0.0 ? -p : p;
		return p;
	}

	/// <summary>
	/// High-accuracy double: half-angle reduction shrinks a ∈ [0,1] to t ∈ [0, tan(π/8)],
	/// then applies an 8-term Taylor series whose truncation error ≤ t^17/17 ≈ 1.8e-8 rad.
	/// Identity used: atan(a) = 2·atan(t),  t = a / (1 + √(1 + a²)).
	/// Max absolute error ≈ 4e-8 rad (including the factor of 2).
	/// </summary>
	private static double FastAtan2DoubleV3(double y, double x)
	{
		if (Double.IsNaN(y) || Double.IsNaN(x)) return Double.NaN;
		var absX = Double.Abs(x);
		var absY = Double.Abs(y);
		var maxV = Double.Max(absX, absY);
		if (maxV == 0.0) return 0.0;

		var a = Double.Min(absX, absY) / maxV; // a ∈ [0, 1]

		// Half-angle reduction: t = a/(1+√(1+a²)) ∈ [0, tan(π/8)] ≈ [0, 0.4142]
		// Identity: atan(a) = 2·atan(t)
		var t = a / (1.0 + Math.Sqrt(1.0 + a * a));
		var u = t * t;

		// 8-term Horner-evaluated Taylor series: atan(t)/t = Σ (−u)^n/(2n+1)
		var p = Double.FusedMultiplyAdd(u, -1.0 / 15.0, 1.0 / 13.0);
		p = Double.FusedMultiplyAdd(u, p, -1.0 / 11.0);
		p = Double.FusedMultiplyAdd(u, p, 1.0 / 9.0);
		p = Double.FusedMultiplyAdd(u, p, -1.0 / 7.0);
		p = Double.FusedMultiplyAdd(u, p, 1.0 / 5.0);
		p = Double.FusedMultiplyAdd(u, p, -1.0 / 3.0);
		p = Double.FusedMultiplyAdd(u, p, 1.0);
		p = 2.0 * t * p; // atan(a) = 2·atan(t)

		p = absY > absX ? Math.PI / 2.0 - p : p;
		p = x < 0.0 ? Math.PI - p : p;
		p = y < 0.0 ? -p : p;
		return p;
	}
}

